<template>
  <div class="symbol-info">
    <div class="symbol-info__choice">
      <select v-model="currentSymbol" @change="change()">
        <option v-for="symbol of symbols" :key="symbol">{{symbol}}</option>
      </select>
    </div>
     {{getSymbol}}
    <p @click="change('btcusdt')">BTCUSDT</p>
    <p @click="change('bnbbtc')">BNBBTC</p>
  </div>
</template>

<script>
import { mapGetters, mapActions } from 'vuex'
export default {
  data: () => ({
    currentSymbol: 'btcusdt',
    symbols: ['btcusdt', 'bnbbtc', 'ethbtc']
  }),
  computed: {
    ...mapGetters(['getSymbol'])
  },
  methods: {
     change() {
       console.log(this.currentSymbol);
      this.changeSymbol(this.currentSymbol)
      this.getInfo()
    },
    ...mapActions(['changeSymbol', 'getInfo'])
  }
}
</script>

